INSERT INTO insights_ai (empresa_id, indicador_key, periodo_ano, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por) VALUES (3104, 'EBITDA_M11', 2025, 'M11', 'success', '[Sesion Gerencial - Noviembre] Te felicito por el vigor operativo que has mostrado en este mes de noviembre. Has logrado que tu capacidad de generacion de beneficios antes de compromisos financieros supere el promedio historico de tus ultimos años, lo cual demuestra que has llegado al cierre del cuarto trimestre con una maquinaria comercial muy bien aceitada y lista para triunfar.', '[Sesion Gerencial - Noviembre] No obstante, debes ser consciente de que el exito de noviembre puede ser efimero si permites que el cansancio del año relaje tus controles de calidad técnica sobre los proyectos finales. Mantener este ritmo de EBITDA exige que sigas vigilando cada hora senior invertida; cualquier descuido en la ejecucion podria erosionar esta gran ventaja competitiva acumulada.', '[Sesion Gerencial - Noviembre] Mi recomendacion para este cierre de ciclo es que realices una reunion de alineacion técnica con tus lideres de proyecto para asegurar que todos los cierres se realicen con la maxima eficiencia. Consolida este exito hoy para que diciembre sea el mes de mayor tranquilidad y solidez patrimonial de toda la historia de tu firma MAS CONSULTA.', 'Sesion de Auditoria Gerencial - Bloque D - Noviembre', 'antigravity') ON CONFLICT (empresa_id, indicador_key, periodo_ano, COALESCE(period_key, 'Annual')) DO UPDATE SET analisis_positivo = EXCLUDED.analisis_positivo, analisis_negativo = EXCLUDED.analisis_negativo, recomendacion = EXCLUDED.recomendacion, updated_at = CURRENT_TIMESTAMP;

