INSERT INTO insights_ai (empresa_id, indicador_key, periodo_ano, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por) VALUES (3104, 'PATRIMONIO_M12', 2025, 'M12', 'success', '[Sesion Gerencial - Diciembre] Haber consolidado una muralla patrimonial tan robusta al cierre de este gran año 2025 es un exito de gestion que te posiciona como un referente de solidez en todo el mercado consultor regional. Este incremento en tu capital propio te da un blindaje total contra imprevistos externos y te permite mirar el futuro 2026 con una tranquilidad financiera que muy pocos competidores tienen.', '[Sesion Gerencial - Diciembre] Te advierto, sin embargo, que tener tanta solidez patrimonial no debe ser excusa para el descuido de los controles de flujo de caja durante las festividades de fin de año. La abundancia de capital propio a veces relaja la disciplina de cobro a clientes corporativos; no permitas que tu patrimonio fuerte financie la desidia de otros; sigue cobrando con el mismo rigor de siempre.', '[Sesion Gerencial - Diciembre] Mi recomendacion ejecutiva es que utilices este respaldo patrimonial para negociar mejores condiciones de escala con tus aliados estrategicos mas importantes. Haz valer tu solvencia real en cada mesa de negociacion; un patrimonio como el tuyo es la mejor tarjeta de presentacion para cerrar contratos mas ambiciosos, recurrentes y rentables durante todo el ciclo venidero.', 'Sesion de Auditoria Gerencial - Bloque D - Diciembre', 'antigravity') ON CONFLICT (empresa_id, indicador_key, periodo_ano, COALESCE(period_key, 'Annual')) DO UPDATE SET analisis_positivo = EXCLUDED.analisis_positivo, analisis_negativo = EXCLUDED.analisis_negativo, recomendacion = EXCLUDED.recomendacion, updated_at = CURRENT_TIMESTAMP;

-- UTILIDAD_M12
INSERT INTO insights_ai (empresa_id, indicador_key, periodo_ano, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por) VALUES (3104, 'UTILIDAD_M12', 2025, 'M12', 'danger', '[Sesion Gerencial - Diciembre] Al cerrar este ciclo anual, rescatamos el hecho de que has logrado mantener la operacion técnica de la firma viva sin comprometer su solidez patrimonial de largo plazo. Seguir operando en un diciembre tan exigente demuestra la resiliencia de tu marca MAS CONSULTA y tu gran capacidad de liderazgo para navegar aguas comerciales turbulentas con vision de gerente senior experto.', '[Sesion Gerencial - Diciembre] Me preocupa notar que la velocidad de acumulacion de beneficios ha caido drásticamente en este cierre de año, superando los retrocesos de diciembres anteriores. Ver que tu utilidad acumulada se erosiona indica que los gastos de temporada o la falta de cobros efectivos estan restando brillo a tu resultado final de gestion, lo cual es un semaforo rojo para tu bolsillo empresarial.', '[Sesion Gerencial - Diciembre] Debes iniciar el proximo ciclo con un plan de choque comercial y operativo para recuperar el terreno perdido en este cierre. Mi consejo ejecutivo es que protejas tu utilidad acumulada evitando retiros desproporcionados durante las festividades; recuerda que cada peso que conserves en la firma hoy sera la semilla de tu gran crecimiento extraordinario en el futuro proximo de 2026.', 'Sesion de Auditoria Gerencial - Bloque D - Diciembre', 'antigravity') ON CONFLICT (empresa_id, indicador_key, periodo_ano, COALESCE(period_key, 'Annual')) DO UPDATE SET analisis_positivo = EXCLUDED.analisis_positivo, analisis_negativo = EXCLUDED.analisis_negativo, recomendacion = EXCLUDED.recomendacion, updated_at = CURRENT_TIMESTAMP;

